  "inline-flex items-center justify-center rounded-md text-sm font-medium ring-offset-background transition-colors hover:bg-muted hover:text-muted-foreground focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ring focus-visible:ring-offset-2 disabled:pointer-events-none disabled:opacity-50 data-[state=on]:bg-accent data-[state=on]:text-accent-foreground",
  {
    variants: {
      variant: {
        default: "bg-transparent",
        outline: "border border-input bg-transparent hover:bg-accent hover:text-accent-foreground",
      },
      size: {
        default: "h-10 px-3",
        sm: "h-9 px-2.5",
        lg: "h-11 px-5",
      },
    },
    defaultVariants: {
      variant: "default",
      size: "default",
    },
  },
);

const Toggle = React.forwardRef<
  React.ElementRef<typeof TogglePrimitive.Root>,
  React.ComponentPropsWithoutRef<typeof TogglePrimitive.Root> & VariantProps<typeof toggleVariants>
>(({ className, variant, size, ...props }, ref) => (
  <TogglePrimitive.Root ref={ref} className={cn(toggleVariants({ variant, size, className }))} {...props} />
));

Toggle.displayName = TogglePrimitive.Root.displayName;

export { Toggle, toggleVariants };

import { useState, useCallback, useEffect } from 'react';
import { supabase } from '@/integrations/supabase/client';
import { useToast } from '@/hooks/use-toast';

export interface ActivityReport {
  id: string;
  studentName: string;
  date: string;
  level: string;
  lessonWeek: number;
  lessonName: string;
  tools: string;
  coach: string;
  coachComment: string;
  goalsMateri: string;
  activityReportText: string;
  mediaUrls: string[];
  externalLinks?: { label: string; url: string }[];
  createdAt: string;
}

interface DbReport {
  id: string;
  student_name: string;
  date: string;
  level: string;
  lesson_week: number;
  lesson_name: string;
  tools: string | null;
  coach: string;
  coach_comment: string | null;
  goals_materi: string | null;
  activity_report_text: string | null;
  media_urls: string[] | null;
  external_links: { label: string; url: string }[] | null;
  created_at: string;
  updated_at: string;
}

function dbToApp(row: DbReport): ActivityReport {
  return {
    id: row.id,
    studentName: row.student_name,
    date: row.date,
    level: row.level,
    lessonWeek: row.lesson_week,
    lessonName: row.lesson_name,
    tools: row.tools || '',
    coach: row.coach,
    coachComment: row.coach_comment || '',
    goalsMateri: row.goals_materi || '',
    activityReportText: row.activity_report_text || '',
    mediaUrls: row.media_urls || [],
    externalLinks: row.external_links || [],
    createdAt: row.created_at,
  };
}

export function useActivityReports(studentName?: string, accessCode?: string) {
  const [reports, setReports] = useState<ActivityReport[]>([]);
  const [loading, setLoading] = useState(true);
  const { toast } = useToast();

  const fetchReports = useCallback(async () => {
    let data: any, error: any;

    if (studentName && accessCode) {
      // @ts-ignore - RPC function created via SQL
      const result = await supabase.rpc('get_student_reports', {
        p_student_name: studentName,
        p_access_code: accessCode
      });

      // Smart Fallback: If function doesn't exist yet, use old direct query
      if (result.error && (result.error.code === 'PGRST202' || result.error.message?.includes('function public.get_student_reports'))) {
        console.warn('Security RPC not found, falling back to direct query');
        const fallback = await supabase
          .from('activity_reports')
          .select('*')
          .eq('student_name', studentName)
          .order('date', { ascending: false });
        data = fallback.data;
        error = fallback.error;
      } else {
        data = result.data;
        error = result.error;
      }
    } else {
      // Use standard query for Admin (Authenticated)
      let query = supabase
        .from('activity_reports')
        .select('*')
        .order('date', { ascending: false });

      if (studentName) {
        query = query.eq('student_name', studentName);
      }

      const result = await query;
      data = result.data;
      error = result.error;
    }


    if (error) {
      console.error('Error fetching reports:', error);
      toast({ title: 'Error', description: 'Gagal memuat laporan.', variant: 'destructive' });
      setLoading(false);
      return;
    }

    setReports((data as DbReport[] || []).map(dbToApp));
    setLoading(false);
  }, [studentName, accessCode, toast]);

  useEffect(() => {
    fetchReports();

    // Realtime subscription ΓÇö mirip dengan useSchedule
    const channel = supabase
      .channel(`activity-reports-realtime${studentName ? `-${studentName}` : ''}`)
      .on(
        'postgres_changes',
        { event: '*', schema: 'public', table: 'activity_reports' },
        () => {
          fetchReports();
        }
      )
      .subscribe();

    return () => {
      supabase.removeChannel(channel);
    };
  }, [fetchReports, studentName, accessCode]);

  const addReport = useCallback(async (report: Omit<ActivityReport, 'id' | 'createdAt'>) => {
    let activityText = report.activityReportText || '';
    if (report.externalLinks && report.externalLinks.length > 0) {
      const linksText = report.externalLinks
        .map(link => `\n≡ƒöù ${link.label || 'Link'}: ${link.url}`)
        .join('');
      activityText += `\n\nVideo Presentasi:${linksText}`;
    }

    const payload: any = {
      student_name: report.studentName,
      date: report.date,
      level: report.level,
      lesson_week: report.lessonWeek,
      lesson_name: report.lessonName,
      tools: report.tools || null,
      coach: report.coach,
      coach_comment: report.coachComment || null,
      goals_materi: report.goalsMateri || null,
      activity_report_text: activityText,
      media_urls: report.mediaUrls,
    };

    const { data, error } = await supabase
      .from('activity_reports')
      .insert(payload)
      .select()
      .single();

    if (error) {
      console.error('Error adding report:', error);
      const msg = error.message || error.code || 'Gagal menambahkan laporan.';
      toast({ title: 'Error', description: msg, variant: 'destructive' });
      return;
    }

    setReports((prev) => [dbToApp(data as DbReport), ...prev]);
    return data;
  }, [toast]);

  const updateReport = useCallback(async (id: string, report: Omit<ActivityReport, 'id' | 'createdAt'>) => {
    let activityText = report.activityReportText || '';
    if (report.externalLinks && report.externalLinks.length > 0) {
      // Avoid duplicating links if they're already in the text (simple check)
      if (!activityText.includes('Video Presentasi:')) {
        const linksText = report.externalLinks
          .map(link => `\n≡ƒöù ${link.label || 'Link'}: ${link.url}`)
          .join('');
        activityText += `\n\nVideo Presentasi:${linksText}`;
      }
    }

    const payload: any = {
      student_name: report.studentName,
      date: report.date,
      level: report.level,
      lesson_week: report.lessonWeek,
      lesson_name: report.lessonName,
      tools: report.tools || null,
      coach: report.coach,
      coach_comment: report.coachComment || null,
      goals_materi: report.goalsMateri || null,
      activity_report_text: activityText,
      media_urls: report.mediaUrls,
    };

    const { data, error } = await supabase
      .from('activity_reports')
      .update(payload)
      .eq('id', id)
      .select()
      .single();

    if (error) {
      console.error('Error updating report:', error);
      const msg = error.message || error.code || 'Gagal memperbarui laporan.';
      toast({ title: 'Error', description: msg, variant: 'destructive' });
      return;
    }

    setReports((prev) => prev.map((r) => (r.id === id ? dbToApp(data as DbReport) : r)));
    return data;
  }, [toast]);

  const deleteReport = useCallback(async (id: string) => {
    const { error } = await supabase.from('activity_reports').delete().eq('id', id);
    if (error) {
      console.error('Error deleting report:', error);
      toast({ title: 'Error', description: 'Gagal menghapus laporan.', variant: 'destructive' });
      return;
    }
    setReports((prev) => prev.filter((r) => r.id !== id));
  }, [toast]);

  return { reports, loading, addReport, updateReport, deleteReport, refetch: fetchReports };
}

export function useAccessCodes() {
  const [codes, setCodes] = useState<{ id: string; studentName: string; accessCode: string }[]>([]);
  const [loading, setLoading] = useState(true);
  const { toast } = useToast();

  const fetchCodes = useCallback(async () => {
    const { data, error } = await supabase
      .from('student_access_codes')
      .select('*')
      .order('student_name');

    if (error) {
      console.error('Error fetching codes:', error);
      setLoading(false);
      return;
    }

    setCodes(
      (data || []).map((r: any) => ({
        id: r.id,
        studentName: r.student_name,
        accessCode: r.access_code,
      }))
    );
    setLoading(false);
  }, []);

  useEffect(() => {
    fetchCodes();
  }, [fetchCodes]);

  const generateCode = useCallback(async (studentName: string) => {
    const code = Math.random().toString(36).substring(2, 8).toUpperCase();
    const { data, error } = await supabase
      .from('student_access_codes')
      .insert({ student_name: studentName, access_code: code })
      .select()
      .single();

    if (error) {
      console.error('Error generating code:', error);
      toast({ title: 'Error', description: 'Gagal membuat kode akses.', variant: 'destructive' });
      return;
    }

    setCodes((prev) => [...prev, { id: data.id, studentName: data.student_name, accessCode: data.access_code }]);
    return data.access_code;
  }, [toast]);

  const deleteCode = useCallback(async (id: string) => {
    const { error } = await supabase.from('student_access_codes').delete().eq('id', id);
    if (error) {
      toast({ title: 'Error', description: 'Gagal menghapus kode akses.', variant: 'destructive' });
      return;
    }
    setCodes((prev) => prev.filter((c) => c.id !== id));
  }, [toast]);

  const lookupByCode = useCallback(async (code: string) => {
    // @ts-ignore - RPC function created via SQL
    const result = await supabase.rpc('verify_student_access', {
      p_access_code: code.toUpperCase()
    });

    let data: any;
    let error: any;
    data = result.data;
    error = result.error;


    // Smart Fallback: If function doesn't exist yet, use old direct query
    if (error && (error.code === 'PGRST202' || error.message?.includes('function public.verify_student_access'))) {
      console.warn('Security RPC not found, falling back to direct query');
      const fallback = await supabase
        .from('student_access_codes')
        .select('*')
        .eq('access_code', code.toUpperCase())
        .maybeSingle();
      data = fallback.data;
      error = fallback.error;
    }

    if (error || !data || (Array.isArray(data) && data.length === 0)) return null;

    // Result matches p_student_name, p_access_code
    const finalResult = Array.isArray(data) ? data[0] : data;
    return { studentName: finalResult.student_name || finalResult.studentName, accessCode: finalResult.access_code || finalResult.accessCode };
  }, []);


  return { codes, loading, generateCode, deleteCode, lookupByCode };
}

export async function uploadReportMedia(file: File): Promise<string | null> {
  const ext = file.name.split('.').pop();
  const path = `${Date.now()}-${Math.random().toString(36).substring(2, 8)}.${ext}`;

  const { error } = await supabase.storage.from('report-media').upload(path, file);
  if (error) {
    console.error('Upload error:', error);
    return null;
  }

  const { data } = supabase.storage.from('report-media').getPublicUrl(path);
  return data.publicUrl;
}

import { useState, useCallback, useEffect } from 'react';
import { supabase } from '@/integrations/supabase/client';
import { useToast } from '@/hooks/use-toast';

export interface AdminNotification {
  id: string;
  message: string;
  isActive: boolean;
  createdAt: string;
  readBy: string[];
}

export function useNotifications() {
  const [notifications, setNotifications] = useState<AdminNotification[]>([]);
  const [loading, setLoading] = useState(true);
  const { toast } = useToast();

  const fetchNotifications = useCallback(async () => {
    const { data, error } = await supabase
      .from('admin_notifications')
      .select('*')
      .order('created_at', { ascending: false });

    if (error) {
      console.error('Error fetching notifications:', error);
      setLoading(false);
      return;
    }

    setNotifications(
      (data || []).map((r: any) => {
        const readMatch = r.message.match(/\[READ:(.*?)\]/);
        const readBy = readMatch ? readMatch[1].split(',').filter(Boolean) : [];
        const cleanMessage = r.message.replace(/\[READ:.*?\]/g, '').trim();

        return {
          id: r.id,
          message: cleanMessage,
          isActive: r.is_active,
          createdAt: r.created_at,
          readBy
        };
      })
    );
    setLoading(false);
  }, []);

  useEffect(() => {
    fetchNotifications();
  }, [fetchNotifications]);

  const addNotification = useCallback(async (message: string) => {
    const { data, error } = await supabase
      .from('admin_notifications')
      .insert({ message })
      .select()
      .single();

    if (error) {
      toast({ title: 'Error', description: 'Gagal menambah notifikasi.', variant: 'destructive' });
      return;
    }

    setNotifications((prev) => [
      { id: data.id, message: data.message, isActive: data.is_active, createdAt: data.created_at, readBy: [] },
      ...prev,
    ]);
    toast({ title: 'Berhasil', description: 'Notifikasi ditambahkan.' });
  }, [toast]);

  const markAsRead = useCallback(async (id: string, coachName: string) => {
    const notification = notifications.find(n => n.id === id);
    if (!notification || notification.readBy.includes(coachName)) return;

    const newReadBy = [...notification.readBy, coachName];
    const rawMessage = `${notification.message} [READ:${newReadBy.join(',')}]`;

    const { error } = await supabase
      .from('admin_notifications')
      .update({ message: rawMessage })
      .eq('id', id);

    if (!error) {
      setNotifications(prev => prev.map(n => n.id === id ? { ...n, readBy: newReadBy } : n));
    }
  }, [notifications]);

  const toggleNotification = useCallback(async (id: string, isActive: boolean) => {
    const { error } = await supabase
      .from('admin_notifications')
      .update({ is_active: isActive })
      .eq('id', id);

    if (error) {
      toast({ title: 'Error', description: 'Gagal mengubah status.', variant: 'destructive' });
      return;
    }

    setNotifications((prev) =>
      prev.map((n) => (n.id === id ? { ...n, isActive } : n))
    );
  }, [toast]);

  const deleteNotification = useCallback(async (id: string) => {
    const { error } = await supabase
      .from('admin_notifications')
      .delete()
      .eq('id', id);

    if (error) {
      toast({ title: 'Error', description: 'Gagal menghapus notifikasi.', variant: 'destructive' });
      return;
    }

    setNotifications((prev) => prev.filter((n) => n.id !== id));
  }, [toast]);

  const activeNotifications = notifications.filter((n) => n.isActive);

  return { notifications, activeNotifications, loading, addNotification, toggleNotification, deleteNotification, markAsRead };
}

import { useState, useCallback, useEffect } from 'react';
import { ScheduleEntry, DayOfWeek, TimeSlot, Coach, StudentLevel } from '@/types/schedule';
import { supabase } from '@/integrations/supabase/client';
import { useToast } from '@/hooks/use-toast';

interface DbScheduleEntry {
  id: string;
  student_name: string;
  coach: string;
  level: string;
  day: string;
  time: string;
  notes: string | null;
  updated_by: string | null;
  created_at: string;
  updated_at: string;
}


function dbToApp(row: DbScheduleEntry): ScheduleEntry {
  let notes = row.notes || undefined;
  let updatedBy = row.updated_by || undefined;
  let isActive = true;
  let inactiveReason = row.notes?.match(/\[INACTIVE:?(.*?)\]/)?.[1] || undefined;

  // Zero-Migration Hack 1: Extract Inactive Status & Reason
  if (notes && notes.includes('[INACTIVE')) {
    isActive = false;
    notes = notes.replace(/\[INACTIVE:?.*?\]\s*/g, '').trim() || undefined;
  }

  // Zero-Migration Hack 2: Extract updated_by from notes if column is missing
  if (!updatedBy && notes && notes.includes('Γ£ì∩╕Å')) {
    const parts = notes.split('Γ£ì∩╕Å');
    if (parts.length > 1) {
      updatedBy = parts[parts.length - 1].trim();
      notes = parts.slice(0, -1).join('Γ£ì∩╕Å').trim() || undefined;
    }
  }

  return {
    id: row.id,
    studentName: row.student_name,
    coach: row.coach as Coach,
    level: row.level as StudentLevel,
    day: row.day as DayOfWeek,
    time: row.time as TimeSlot,
    isActive,
    notes: notes,
    updatedBy: updatedBy,
    updatedAt: row.updated_at,
  };
}



export function useSchedule() {
  const [schedule, setSchedule] = useState<ScheduleEntry[]>([]);
  const [loading, setLoading] = useState(true);
  const { toast } = useToast();

  const fetchSchedule = useCallback(async () => {
    let { data, error } = await supabase
      .from('schedule_entries')
      .select('*')
      .order('time', { ascending: true });

    // Fallback if updated_by column is missing or schema cache is stale
    if (error && (error.code === '42703' || error.code === 'PGRST204' || error.message?.includes('updated_by'))) {
      const fallback = await supabase
        .from('schedule_entries')
        .select('id, student_name, coach, level, day, time, notes, created_at, updated_at')
        .order('time', { ascending: true });
      data = fallback.data;
      error = fallback.error;
    }


    if (error) {
      console.error('Error fetching schedule:', error);
      toast({
        title: 'Error',
        description: 'Gagal memuat jadwal dari database.',
        variant: 'destructive',
      });
      setLoading(false);
      return;
    }

    setSchedule((data || []).map((row: any) => dbToApp(row as DbScheduleEntry)));
    setLoading(false);
  }, [toast]);



  useEffect(() => {
    fetchSchedule();

    // Realtime subscription
    const channel = supabase
      .channel('schedule-realtime')
      .on(
        'postgres_changes',
        { event: '*', schema: 'public', table: 'schedule_entries' },
        () => {
          fetchSchedule();
        }
      )
      .subscribe();

    return () => {
      supabase.removeChannel(channel);
    };
  }, [fetchSchedule]);

  const addEntry = useCallback(async (entry: Omit<ScheduleEntry, 'id'>) => {
    let finalNotes = entry.notes || '';
    if (entry.isActive === false) {
      finalNotes = `[INACTIVE] ${finalNotes}`.trim();
    }

    const insertData: any = {
      student_name: entry.studentName,
      coach: entry.coach,
      level: entry.level,
      day: entry.day,
      time: entry.time,
      notes: finalNotes || null,
    };

    // Only add updated_by if we're reasonably sure it exists or just try and handle error
    // For now, let's try to insert with it, and if it fails with 'column does not exist', try without it
    const { data, error } = await supabase
      .from('schedule_entries')
      .insert({ ...insertData, updated_by: entry.updatedBy || null })
      .select()
      .single();

    if (error) {
      console.warn('Original addEntry error:', error);
      if (error.message?.includes('column "updated_by" of relation "schedule_entries" does not exist') ||
        error.message?.includes('updated_by') ||
        error.code === '42703' ||
        error.code === 'PGRST204') {

        const notesWithAudit = entry.updatedBy
          ? (entry.notes ? `${entry.notes}\nΓ£ì∩╕Å ${entry.updatedBy}` : `Γ£ì∩╕Å ${entry.updatedBy}`)
          : entry.notes;

        const { data: retryData, error: retryError } = await supabase
          .from('schedule_entries')
          .insert({ ...insertData, notes: notesWithAudit })
          .select()
          .single();


        if (retryError) {
          console.error('Error adding entry (retry):', retryError);
          toast({
            title: 'Error (Retry)',
            description: `Gagal: ${retryError.message} (${retryError.code})`,
            variant: 'destructive',
          });
          return;
        }
        setSchedule((prev) => [...prev, dbToApp({ ...retryData, updated_by: entry.updatedBy } as DbScheduleEntry)]);

        return;
      }

      console.error('Error adding entry:', error);
      toast({
        title: 'Error',
        description: `Gagal menambahkan jadwal: ${error.message} (${error.code})`,
        variant: 'destructive',
      });
      return;
    }

    setSchedule((prev) => [...prev, dbToApp(data as DbScheduleEntry)]);
  }, [toast]);

  const updateEntry = useCallback(async (id: string, updates: Partial<Omit<ScheduleEntry, 'id'>>) => {
    const existingEntry = schedule.find(e => e.id === id);
    if (!existingEntry) return;

    const dbUpdates: Record<string, unknown> = {};
    if (updates.studentName !== undefined) dbUpdates.student_name = updates.studentName;
    if (updates.coach !== undefined) dbUpdates.coach = updates.coach;
    if (updates.level !== undefined) dbUpdates.level = updates.level;
    if (updates.day !== undefined) dbUpdates.day = updates.day;
    if (updates.time !== undefined) dbUpdates.time = updates.time;

    // Determine the base notes (what the user typed, ignoring internal tags)
    let baseNotes = updates.notes !== undefined ? updates.notes : existingEntry.notes;
    let finalIsActive = updates.isActive !== undefined ? updates.isActive : existingEntry.isActive;
    let finalReason = updates.inactiveReason !== undefined ? updates.inactiveReason : existingEntry.inactiveReason;

    // Inject or remove [INACTIVE]
    let finalNotes = baseNotes || '';
    if (!finalIsActive) {
      const tag = finalReason ? `[INACTIVE:${finalReason}]` : '[INACTIVE]';
      finalNotes = `${tag} ${finalNotes}`.trim();
    }

    dbUpdates.notes = finalNotes || null;

    // Attempt with updated_by first
    const dbUpdatesWithAudit = { ...dbUpdates };
    if (updates.updatedBy !== undefined) dbUpdatesWithAudit.updated_by = updates.updatedBy;

    const { error } = await supabase
      .from('schedule_entries')
      .update(dbUpdatesWithAudit)
      .eq('id', id);

    if (error) {
      if (error.message?.includes('column "updated_by" of relation "schedule_entries" does not exist') ||
        error.message?.includes('updated_by') ||
        error.code === '42703' ||
        error.code === 'PGRST204') {

        const targetNotes = finalNotes;
        const notesWithAudit = updates.updatedBy
          ? (targetNotes ? `${targetNotes}\nΓ£ì∩╕Å ${updates.updatedBy}` : `Γ£ì∩╕Å ${updates.updatedBy}`)
          : targetNotes;

        const { error: retryError } = await supabase
          .from('schedule_entries')
          .update({ ...dbUpdates, notes: notesWithAudit || null })
          .eq('id', id);

        if (retryError) {
          console.error('Error updating entry (retry):', retryError);
          toast({
            title: 'Error',
            description: 'Gagal memperbarui jadwal.',
            variant: 'destructive',
          });
          return;
        }

        setSchedule((prev) =>
          prev.map((entry) => (entry.id === id ? { ...entry, ...updates, notes: targetNotes, updatedBy: updates.updatedBy || entry.updatedBy } : entry))
        );
        return;
      }

      console.error('Error updating entry:', error);
      toast({
        title: 'Error',
        description: 'Gagal memperbarui jadwal.',
        variant: 'destructive',
      });
      return;
    }

    setSchedule((prev) =>
      prev.map((entry) => (entry.id === id ? { ...entry, ...updates } : entry))
    );
  }, [toast, schedule]);

  const deleteEntry = useCallback(async (id: string) => {
    const { error } = await supabase
      .from('schedule_entries')
      .delete()
      .eq('id', id);

    if (error) {
      console.error('Error deleting entry:', error);
      toast({
        title: 'Error',
        description: 'Gagal menghapus jadwal.',
        variant: 'destructive',
      });
      return;
    }

    setSchedule((prev) => prev.filter((entry) => entry.id !== id));
  }, [toast]);

  const getEntriesForCell = useCallback(
    (day: DayOfWeek, time: TimeSlot) => {
      return schedule.filter((entry) => entry.day === day && entry.time === time);
    },
    [schedule]
  );

  return {
    schedule,
    loading,
    addEntry,
    updateEntry,
    deleteEntry,
    getEntriesForCell,
  };
}

import { useState, useCallback, useEffect, useRef } from 'react';
import { Header } from '@/components/Header';
import { StatsCards } from '@/components/StatsCards';
import { ScheduleGrid } from '@/components/ScheduleGrid';
import { ScheduleDialog } from '@/components/ScheduleDialog';
import { DeleteConfirmDialog } from '@/components/DeleteConfirmDialog';
import { RunningText } from '@/components/RunningText';
import { NotificationManager } from '@/components/NotificationManager';
import { NotificationHistory } from '@/components/NotificationHistory';
import { useSchedule } from '@/hooks/useSchedule';
import { useNotifications } from '@/hooks/useNotifications';
import { ScheduleEntry, DayOfWeek, TimeSlot, Coach, COACHES } from '@/types/schedule';
import { Plus, Filter, X, Eye, EyeOff, Bell } from 'lucide-react';
import { Button } from '@/components/ui/button';
import { useToast } from '@/hooks/use-toast';
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from '@/components/ui/select';
import { Skeleton } from '@/components/ui/skeleton';
import { Tabs, TabsContent, TabsList, TabsTrigger } from '@/components/ui/tabs';
import { useAuth } from '@/hooks/useAuth';


import { WelcomeHero } from '@/components/WelcomeHero';
import { AnalyticsBento } from '@/components/AnalyticsBento';


const Index = () => {
  const { schedule, loading: scheduleLoading, addEntry, updateEntry, deleteEntry, getEntriesForCell } = useSchedule();
  const { notifications, activeNotifications, addNotification, toggleNotification, deleteNotification, markAsRead } = useNotifications();
  const { user } = useAuth();
  const { toast } = useToast();

  const coachName = user?.user_metadata?.full_name || user?.email?.split('@')[0] || 'Coach';
  const displayedCoachName = coachName.split(/[._-]/).map((w: any) => w.charAt(0).toUpperCase() + w.slice(1)).join(' ');

  // Toast logic for new notifications
  const toastedIds = useRef<Set<string>>(new Set());

  useEffect(() => {
    const coachNotifications = activeNotifications.filter(n => !n.message.startsWith('[PARENT]'));

    coachNotifications.forEach(n => {
      const isUnread = !n.readBy.includes(displayedCoachName);
      if (isUnread && !toastedIds.current.has(n.id)) {
        const { dismiss } = toast({
          title: "Update Baru! ≡ƒôó",
          description: n.message,
          duration: Infinity,
          action: (
            <Button size="sm" variant="outline" onClick={() => {
              markAsRead(n.id, displayedCoachName);
              dismiss();
            }} className="h-9 sm:h-8 font-bold text-[11px] sm:text-[10px] px-3">
              SAYA MENGERTI
            </Button>
          ),
        });
        toastedIds.current.add(n.id);
      }
    });

    // Cleanup toastedIds for notifications that were deleted
    const currentIds = Array.from(toastedIds.current);
    currentIds.forEach(id => {
      if (!notifications.find(n => n.id === id)) {
        toastedIds.current.delete(id);
      }
    });
  }, [activeNotifications, displayedCoachName, markAsRead, toast, notifications]);


  const [filterCoach, setFilterCoach] = useState<Coach | 'all'>('all');
  const [filterLevel, setFilterLevel] = useState<string>('all');

  const [filterActive, setFilterActive] = useState<boolean>(true);

  const filteredGetEntriesForCell = useCallback(
    (day: DayOfWeek, time: TimeSlot) => {
      return getEntriesForCell(day, time).filter((entry) => {
        const matchCoach = filterCoach === 'all' || entry.coach === filterCoach;
        const matchLevel =
          filterLevel === 'all' ||
          (filterLevel === 'Little Creator' && entry.level.startsWith('Little Creator')) ||
          (filterLevel === 'Junior' && entry.level.startsWith('Junior')) ||
          (filterLevel === 'Teenager' && entry.level.startsWith('Teenager'));
        const matchActive = !filterActive || entry.isActive;
        return matchCoach && matchLevel && matchActive;
      });
    },
    [getEntriesForCell, filterCoach, filterLevel, filterActive]
  );

  const hasActiveFilter = filterCoach !== 'all' || filterLevel !== 'all' || !filterActive;

  const clearFilters = () => {
    setFilterCoach('all');
    setFilterLevel('all');
    setFilterActive(true);
  };


  const [dialogOpen, setDialogOpen] = useState(false);
  const [editingEntry, setEditingEntry] = useState<ScheduleEntry | null>(null);
  const [defaultDay, setDefaultDay] = useState<DayOfWeek>('senin');
  const [defaultTime, setDefaultTime] = useState<TimeSlot>('08:00');

  const [deleteDialogOpen, setDeleteDialogOpen] = useState(false);
  const [deletingEntry, setDeletingEntry] = useState<ScheduleEntry | null>(null);

  const handleAddClick = (day: DayOfWeek, time: TimeSlot) => {
    setEditingEntry(null);
    setDefaultDay(day);
    setDefaultTime(time);
    setDialogOpen(true);
  };

  const handleEditClick = (entry: ScheduleEntry) => {
